root.sql:
select sc_acc_t_trial_balance_rep.account_id, sc_acc_m_account_master.account_name, sc_acc_m_ucf_account_group.account_group_id, sc_acc_m_ucf_account_group.account_group_name, sc_acc_t_trial_balance_rep.dr_bb, sc_acc_t_trial_balance_rep.cr_bb, sc_acc_t_trial_balance_rep.dr_between, sc_acc_t_trial_balance_rep.cr_between, sc_acc_t_trial_balance_rep.dr_amount, sc_acc_t_trial_balance_rep.cr_amount from sc_acc_t_trial_balance_rep, sc_acc_m_account_master, sc_acc_m_ucf_account_group where sc_acc_t_trial_balance_rep.account_id = sc_acc_m_account_master.account_id and sc_acc_m_account_master.account_group_id = sc_acc_m_ucf_account_group.account_group_id
and ( sc_acc_t_trial_balance_rep.dr_bb > 0 or sc_acc_t_trial_balance_rep.cr_bb > 0 or sc_acc_t_trial_balance_rep.dr_between > 0 or sc_acc_t_trial_balance_rep.cr_between > 0 or sc_acc_t_trial_balance_rep.dr_amount > 0 or sc_acc_t_trial_balance_rep.cr_amount > 0 )
/*WHERE*/ order by sc_acc_t_trial_balance_rep.account_id
